mapper.select:
SELECT

FROM assist_storage a
WHERE id = #{id}

SELECT

FROM assist_storage a

    del_flag = #{DEL_FLAG_NORMAL}

        AND mime_type = #{queryMimeType}


        AND business_id = #{queryBusinessId}


        AND business_type = #{queryBusinessType}


        AND owner_id = #{queryOwnerId}


        AND owner_type = #{queryOwnerType}


        AND enable_flag = #{queryEnableFlag}


        AND public_flag = #{queryPublicFlag}


        AND name LIKE CONCAT('%', #{queryName}, '%')


        AND remarks LIKE CONCAT('%', #{queryRemarks}, '%')


ORDER BY a.create_date DESC, a.priority

mapper.update:
UPDATE assist_storage
SET enable_flag = #{enableFlag},
    update_date = #{updateDate}
WHERE id = #{id}

UPDATE assist_storage
SET public_flag = #{publicFlag},
    update_date = #{updateDate}
WHERE id = #{id}

UPDATE assist_storage
SET business_id = CASE id

        WHEN #{item.id} THEN #{item.businessId}

    END,
    business_type = CASE id

        WHEN #{item.id} THEN #{item.businessType}

    END,
    business_params = CASE id

        WHEN #{item.id} THEN #{item.businessParams}

    END,
    public_flag = CASE id

        WHEN #{item.id} THEN #{item.publicFlag}

    END,
    update_date = CURRENT_TIMESTAMP
WHERE id IN
#{item.id}
